private struct GeminiChatScreen: View {
    @State private var draft = ""
    var body: some View {
        VStack(spacing: 0) {
            ScrollView {
                VStack(spacing: 12) {
                    ForEach(GeminiDemoData.messages) { msg in
                        if msg.isUser { GeminiUserBubble(text: msg.text, accent: GeminiTokens.gemTextPrimary) }
                        else { GeminiAssistantBubble(text: msg.text, surface: GeminiTokens.gemSurface) }
                    }
                }.padding()
            }.background(GeminiTokens.gemCanvas.ignoresSafeArea())
            HStack(spacing: 12) {
                TextField("Message Gemini…", text: $draft, axis: .vertical).padding(10).background(RoundedRectangle(cornerRadius: 20).fill(GeminiTokens.gemSurface))
                Button {} label: { Image(systemName: "arrow.up.circle.fill").font(.title2).foregroundStyle(GeminiTokens.gemTextPrimary) }
            }.padding().background(.bar)
        }
    }
}

private struct GeminiUserBubble: View {
    let text: String; let accent: Color
    var body: some View { HStack { Spacer(minLength: 48); Text(text).padding(12).background(RoundedRectangle(cornerRadius: 16).fill(accent.opacity(0.15))) } }
}

private struct GeminiAssistantBubble: View {
    let text: String; let surface: Color
    var body: some View { HStack { Text(text).padding(12).background(RoundedRectangle(cornerRadius: 16).fill(surface)); Spacer(minLength: 48) } }
}

private struct GeminiChatMsg: Identifiable { let id = UUID(); let text: String; let isUser: Bool }
private enum GeminiDemoData {
    static let messages: [GeminiChatMsg] = [
        .init(text: "Explique-moi le métro parisien", isUser: true),
        .init(text: "Le métro parisien compte 16 lignes numérotées. La ligne 1 traverse Paris d'ouest en est.", isUser: false),
        .init(text: "Quel ticket acheter ?", isUser: true),
        .init(text: "Pour un touriste, le pass Navigo Jour ou des tickets t+ sont les options les plus courantes.", isUser: false),
    ]
}

private struct GeminiGenericListScreen: View {
    let title: String
    var body: some View {
        NavigationStack {
            List(0..<8, id: \.self) { i in
                HStack {
                    RoundedRectangle(cornerRadius: 8).fill(GeminiTokens.gemTextPrimary.opacity(0.15)).frame(width: 44, height: 44)
                    VStack(alignment: .leading) {
                        Text("\(title) \(i + 1)").font(.system(size: 17, weight: .semibold))
                        Text("Mis à jour récemment").font(.system(size: 14)).foregroundStyle(.secondary)
                    }
                }
            }
            .navigationTitle(title)
        }
    }
}
